{
  "questions": [
    {
      "format": "sortOrder",
      "question": "You type a URL and hit enter. Put these lifecycle stages in the order they actually happen.",
      "items": [
        "Browser resolves the domain name to an IP address",
        "Browser establishes a TCP connection with the server",
        "Browser completes a TLS handshake to secure the connection",
        "Browser sends the HTTP request for the page",
        "Server sends back the requested HTML",
        "Browser parses the HTML and builds the DOM, then renders the page"
      ],
      "feedback": "Each step depends on the one before it: you need an IP address before you can connect, a connection before you can encrypt it, encryption (for HTTPS) before sending data, a request before a response, and a response before there's anything to parse and render."
    },
    {
      "format": "multipleChoice",
      "context": "A reader revisits a news site she opened an hour ago. Even though the server takes the same time to assemble the page, the site feels noticeably snappier this time.",
      "question": "What's the most likely reason?",
